def solve_plantui(node):
    node = node.split(':')

    for i, node1 in enumerate(node[::-1]):
        for j, node2 in enumerate(node1[::-1]):
            if node2 == node[0]:
                continue
            if node1[-1] != node2[:-1]:
                raise ValueError('Error occurred: ' + str(node[i][::-1]))

